serverCode:
$links = array();

while($record = $button->getNextSelectedRecord())
{
    $nama = $record["nama"];
    $nik  = $record["nik"];
    $hp   = $record["hp_pasien"];

    if(empty($hp)){
        continue;
    }

    $hp = preg_replace('/[^0-9]/', '', $hp);

    if(substr($hp,0,1) == "0"){
        $hp = "62" . substr($hp,1);
    }

    $pesan = "Assalamu'alaikum Bapak/Ibu yang bernama: ".$nama.
             ", dengan NIK: ".$nik.
             ", harap hadir pada hari Kamis";

    $link = "https://api.whatsapp.com/send?phone=".$hp."&text=".urlencode($pesan);

    $links[] = $link;
}

if(count($links) == 0){
    $result["error"] = "Tidak ada nomor HP valid";
    return;
}

$result["wa_links"] = $links;

