afterJsCode:
if(result.error){
    alert(result.error);
} else {

    var links = result.wa_links;
    var i = 0;

    var waTab = window.open("", "_blank");

    function kirimBerikutnya() {

        if(i >= links.length){
            alert("Selesai kirim ke " + links.length + " nomor");
            return;
        }

        waTab.location.href = links[i];

        i++;

        // beri waktu cukup agar user klik kirim
        setTimeout(kirimBerikutnya, 12000); // 12 detik
    }

    kirimBerikutnya();
}
